def process_graph(graph_data):

    graph_copy = copy.deepcopy(graph_data)
    agg_block_name = 'ju1.a2.m3'
    results = []

    for node in graph_copy.nodes(data=True):
        if 'EK_AGG_BLOCK' in node[1]['type'] and node[1]['name'] == agg_block_name:
            agg_node = node[0]
            break

    for edge in graph_copy.out_edges(agg_node, data=True):
        if 'RK_CONTAINS' in edge[2]['type']:
            child_node = edge[1]
            child_data = graph_copy.nodes[child_node]

            if 'physical_capacity_bps' in child_data:
                capacity = child_data['physical_capacity_bps']
            else:
                capacity = 0
                for port_edge in nx.dfs_edges(graph_copy, source=child_node):
                    if 'RK_CONTAINS' in graph_copy.edges[port_edge]['type']:
                        port_node = port_edge[1]
                        port_data = graph_copy.nodes[port_node]
                        if 'physical_capacity_bps' in port_data:
                            capacity += port_data['physical_capacity_bps']

            results.append((child_data['name'], capacity))

    results.sort(key=lambda x: x[1], reverse=True)

    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
    return_object = {
        'type': 'list',
        'data': results,
        'updated_graph': graph_json
    }
    return return_object

